{
float[] new_values=new float[9];
new_values=values;
values=mult(states,values,new_values);
for(int i=0;i<9;i++)
{
values[i]= reward[i]+ values[i]*gamma;
}
float max_values= maxi(values);
int max_index=maxi_index(values,max_values);
return max_index;
}
